Bối cảnh: [Logistics]
Đề bài: Công ty Logistics 'Giao Hàng Xuyên Việt' đang xử lý một danh sách gồm N mã kiện hàng (mã số nguyên). Do lỗi từ trạm quét mã, một số kiện hàng bị quét lặp lại nhiều lần. Bạn được yêu cầu viết một chương trình C để đếm tổng số cặp mã kiện hàng bị trùng lặp trong danh sách này để bộ phận vận hành đối soát lại doanh thu. Giới hạn: N có thể lên tới 200,000 mã kiện hàng.
Code:
#include <stdio.h>
#include <stdlib.h>

// Hàm đếm số cặp trùng lặp bằng cách so sánh từng cặp một
long long count_duplicate_pairs(int *arr, int n) {
    long long pairs = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            if (arr[i] == arr[j]) {
                pairs++;
            }
        }
    }
    return pairs;
}

int main() {
    int n;
    printf("Nhap so luong kien hang: ");
    if (scanf("%d", &n) != 1) return 0;

    int *packages = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &packages[i]);
    }

    long long result = count_duplicate_pairs(packages, n);
    printf("Tong so cap trung lap: %lld\n", result);

    free(packages);
    return 0;
}
Lỗi: Time Limit Exceeded trên tập dữ liệu N = 200,000. Thời gian thực hiện vượt quá 10 giây (Giới hạn hệ thống: 1.0 giây).

Bối cảnh: [Social Media]
Đề bài: Hệ thống Social Media 'ConnectX' cần tính năng 'Gợi ý kết bạn'. Cho N người dùng (N <= 100,000), mỗi người dùng có một danh sách gồm tối đa 20 ID sở thích (interests). Một cặp người dùng được gọi là 'Tương đồng nhất' nếu họ có số lượng sở thích chung nhiều nhất. Nhiệm vụ của bạn là lập trình hàm tìm ra số lượng sở thích chung lớn nhất giữa bất kỳ hai người dùng nào trong hệ thống.
Code:
#include <stdio.h>
#include <stdlib.h>

#define MAX_INTERESTS 20

typedef struct {
    int id;
    int interests[MAX_INTERESTS];
    int count;
} User;

int count_common(User u1, User u2) {
    int common = 0;
    for (int i = 0; i < u1.count; i++) {
        for (int j = 0; j < u2.count; j++) {
            if (u1.interests[i] == u2.interests[j]) {
                common++;
                break;
            }
        }
    }
    return common;
}

int main() {
    int n = 100000; // Giả lập N người dùng lớn
    User* users = (User*)malloc(n * sizeof(User));

    // Giả định dữ liệu đã được nạp vào mảng users...

    int max_common = 0;
    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            int current_common = count_common(users[i], users[j]);
            if (current_common > max_common) {
                max_common = current_common;
            }
        }
    }

    printf("Max common interests: %d\n", max_common);
    free(users);
    return 0;
}
Lỗi: Time Limit Exceeded trên dữ liệu N = 100,000. Thời gian thực thi dự kiến: ~1,500 giây. Giới hạn cho phép: 1 giây.

Bối cảnh: [Game]
Đề bài: Trong một trò chơi 'Bullet Hell' (mưa đạn), hệ thống cần xử lý va chạm giữa N viên đạn (projectiles) và M quái vật (monsters) trên màn hình. Mỗi thực thể được định nghĩa bởi tọa độ (x, y) và bán kính va chạm r. Nhiệm vụ của bạn là viết một hàm kiểm tra và đếm tổng số cặp (viên đạn, quái vật) đang xảy ra va chạm. Giả sử màn hình có kích thước 1000x1000, số lượng đạn N có thể lên tới 100.000 và số lượng quái vật M là 10.000. Bạn cần hoàn thành xử lý trong mỗi khung hình (60 FPS).
Code:
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

typedef struct {
    double x, y, r;
} Entity;

// Hàm tính khoảng cách Euclid bình phương để tránh dùng sqrt() - đã cố gắng tối ưu nhẹ
double is_colliding(Entity a, Entity b) {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    double distance_sq = dx * dx + dy * dy;
    double radius_sum = a.r + b.r;
    return distance_sq <= (radius_sum * radius_sum);
}

int count_collisions(Entity* bullets, int n, Entity* monsters, int m) {
    int count = 0;
    // Duyệt qua từng viên đạn
    for (int i = 0; i < n; i++) {
        // Với mỗi viên đạn, duyệt qua tất cả quái vật
        for (int j = 0; j < m; j++) {
            if (is_colliding(bullets[i], monsters[j])) {
                count++;
            }
        }
    }
    return count;
}

int main() {
    int N = 100000; // Số lượng đạn
    int M = 10000;  // Số lượng quái vật
    Entity* bullets = malloc(N * sizeof(Entity));
    Entity* monsters = malloc(M * sizeof(Entity));

    // Giả lập dữ liệu ngẫu nhiên
    for(int i=0; i<N; i++) bullets[i] = (Entity){rand()%1000, rand()%1000, 2};
    for(int i=0; i<M; i++) monsters[i] = (Entity){rand()%1000, rand()%1000, 10};

    int total = count_collisions(bullets, N, monsters, M);
    printf("Total collisions: %d\n", total);

    free(bullets);
    free(monsters);
    return 0;
}
Lỗi: Time Limit Exceeded. Thực thi mất > 10.0 giây cho N=100.000, M=10.000. Yêu cầu khung hình: < 0.016 giây (16ms).

Bối cảnh: [Logistics]
Đề bài: Hệ thống quản lý Logistics cần một hàm khởi tạo nhanh thông tin kiện hàng (Package) bao gồm mã định danh (ID) và trọng lượng (Weight). Để tối ưu hiệu suất và tránh việc sao chép toàn bộ cấu trúc dữ liệu lớn, sinh viên được yêu cầu viết một hàm trả về một con trỏ (pointer) trỏ đến thông tin kiện hàng vừa tạo để các bộ phận khác trong kho (như bộ phận vận chuyển, kiểm kê) có thể truy cập trực tiếp.
Code:
#include <stdio.h>

struct Package {
    int id;
    float weight;
};

struct Package* create_package(int id, float weight) {
    struct Package pkg; // Khởi tạo biến cục bộ trên Stack
    pkg.id = id;
    pkg.weight = weight;

    printf("Log: Dang khoi tao kien hang %d tai dia chi %p\n", pkg.id, &pkg);
    return &pkg; // Tra ve dia chi cua bien cuc bo
}

int main() {
    struct Package *p1 = create_package(101, 50.5);

    // Gia su co mot vai thao tac khac thuc thi tai day
    printf("--- Thong tin kien hang trong kho ---\n");

    // Truy cap vao con tro da nhan
    if (p1 != NULL) {
        printf("ID kien hang: %d\n", p1->id);
        printf("Trong luong: %.2f kg\n", p1->weight);
    }

    return 0;
}
